  ('b8c8a150-92da-45b3-89c1-f9a3039f163b', 'tallow-cream-foundation', 'Tallow Cream Foundation', 'Christian Beauty Co.', 'Christian Beauty Co. is an explicitly faith-based clean beauty brand. Their own mission statement states faith calls them to a higher standard where skincare is rooted in values that honor both body and spirit.', 1, ARRAY['https://www.christianbeautyco.com/discernly'], 'https://www.christianbeautyco.com/products/tallow-cream-foundation?sca_ref=11765311.nBjYCINV1gor', 'direct', 'Beauty & Makeup', 'https://www.christianbeautyco.com/cdn/shop/files/TALLOW_CREAM_FOUNDATION.png?v=1765925591&width=1240', NULL, 'christian'),
